            return .{ .arg = std.mem.readInt(u16, b[1..][0..2], .big), .head = 3 };
        },
        26 => {
            if (b.len < 5) return error.UnexpectedEof;
            return .{ .arg = std.mem.readInt(u32, b[1..][0..4], .big), .head = 5 };
        },
        27 => {
